// Валидация входных данных
const message = $input.first().json.message;

if (!message || !message.text || !message.chat) {
  throw new Error('Некорректное сообщение: отсутствует текст или chat.id');
}

const text = message.text.trim();
if (text.length === 0) {
  throw new Error('Пустое сообщение');
}

// Rate limiting check (простая реализация)
const chatId = message.chat.id;
const now = Date.now();
const oneMinuteAgo = now - 60000;

// Возвращаем очищенные данные
return {
  json: {
    chatId: chatId,
    userId: message.from?.id || chatId,
    text: text,
    messageId: message.message_id,
    timestamp: now,
    firstName: message.from?.first_name || 'User',
    userName: message.from?.username || null
  }
};

// Skill-based Memory Manager
// Консолидированное управление памятью для всех агентов

const chatId = $('Validate Input').item.json.chatId;
const userId = $('Validate Input').item.json.userId;
const text = $('Validate Input').item.json.text;
const timestamp = Date.now();

// Получаем текущую историю из предыдущего шага или создаем новую
let memoryData = {};
try {
  // Пытаемся получить из предыдущего состояния (если есть)
  memoryData = $(this).first().json.memory || {};
} catch (e) {
  memoryData = {};
}

// Инициализируем структуру памяти для чата, если нет
if (!memoryData[chatId]) {
  memoryData[chatId] = {
    userId: userId,
    sessionStart: timestamp,
    lastActivity: timestamp,
    messages: [],
    context: {
      currentAgent: null,
      activeSkills: [],
      preferences: {}
    },
    metadata: {
      totalMessages: 0,
      errors: []
    }
  };
}

// Добавляем новое сообщение (храним последние 10 для контекста)
const newMessage = {
  role: 'user',
  content: text,
  timestamp: timestamp,
  detectedIntent: null // Будет заполнено оркестратором
};

memoryData[chatId].messages.push(newMessage);
memoryData[chatId].lastActivity = timestamp;
memoryData[chatId].metadata.totalMessages++;

// Ограничиваем историю последними 10 сообщениями
if (memoryData[chatId].messages.length > 10) {
  memoryData[chatId].messages = memoryData[chatId].messages.slice(-10);
}

// Обновляем метаданные сессии
const sessionDuration = timestamp - memoryData[chatId].sessionStart;
memoryData[chatId].metadata.sessionDuration = sessionDuration;

return {
  json: {
    chatId,
    userId,
    text,
    memory: memoryData,
    chatHistory: memoryData[chatId].messages,
    context: memoryData[chatId].context,
    metadata: memoryData[chatId].metadata
  }
};

// Orchestrator with Skill-Based Architecture
// Минимальный промпт + динамический skill registry

const text = $('Memory Manager').item.json.text;
const chatHistory = $('Memory Manager').item.json.chatHistory;
const context = $('Memory Manager').item.json.context;

// Skill Registry - компактное описание возможностей
const skills = [
  {
    id: 'calendar',
    name: 'Calendar Agent',
    keywords: ['календарь', 'встреча', 'событие', 'напомин', 'запланируй', 'запиши', 'дата', 'время', 'когда', 'через', 'завтра', 'сегодня', 'неделю', 'месяц'],
    description: 'Управление календарем: создание, чтение, обновление, удаление событий',
    enabled: true
  },
  {
    id: 'clarification',
    name: 'Clarification Agent',
    keywords: ['не понял', 'уточни', 'что значит', 'как', 'почему', 'объясни'],
    description: 'Запрос уточнений у пользователя при неоднозначности',
    enabled: true
  },
  {
    id: 'default',
    name: 'Default Chat',
    keywords: [],
    description: 'Обычный разговор, ответы на общие вопросы',
    enabled: true
  }
];

// Простой классификатор на основе ключевых слов
const textLower = text.toLowerCase();
let detectedSkill = skills.find(s => 
  s.enabled && s.keywords.some(k => textLower.includes(k))
);

// Если не найдено точное совпадение, используем дефолт
if (!detectedSkill) {
  detectedSkill = skills.find(s => s.id === 'default');
}

// Формируем минимальный контекст для выбранного скилла
const skillContext = {
  selectedSkill: detectedSkill.id,
  skillName: detectedSkill.name,
  skillDescription: detectedSkill.description,
  confidence: detectedSkill.id === 'default' ? 0.5 : 0.9
};

// Сокращаем историю до последних 5 сообщений для экономии токенов
const recentHistory = chatHistory.slice(-5).map(msg => 
  `${msg.role}: ${msg.content}`
).join('\n');

return {
  json: {
    ...$('Memory Manager').item.json,
    orchestrator: {
      detectedIntent: detectedSkill.id,
      selectedAgent: detectedSkill.name,
      skillRegistry: skills.filter(s => s.enabled),
      skillContext: skillContext,
      confidence: skillContext.confidence,
      recentHistory: recentHistory,
      shouldRouteToAgent: detectedSkill.id !== 'default'
    }
  }
};

// Calendar Agent with Skills
// Оптимизированный агент с минимальным промптом и отдельными скиллами

const text = $('Orchestrator').item.json.text;
const recentHistory = $('Orchestrator').item.json.orchestrator.recentHistory;
const skillContext = $('Orchestrator').item.json.orchestrator.skillContext;

// Calendar Skills - отдельные функции без раздувания промпта
const calendarSkills = {
  create_event: {
    name: 'create_event',
    description: 'Создать новое событие в календаре',
    parameters: ['title', 'date', 'time', 'duration', 'description'],
    prompt: 'Извлеки данные для создания события: название, дата, время, длительность, описание'
  },
  read_events: {
    name: 'read_events',
    description: 'Просмотреть события за период',
    parameters: ['start_date', 'end_date', 'limit'],
    prompt: 'Определи период для просмотра событий'
  },
  update_event: {
    name: 'update_event',
    description: 'Обновить существующее событие',
    parameters: ['event_id', 'new_title', 'new_date', 'new_time'],
    prompt: 'Найди событие и новые параметры для обновления'
  },
  delete_event: {
    name: 'delete_event',
    description: 'Удалить событие из календаря',
    parameters: ['event_id', 'confirm'],
    prompt: 'Идентифицируй событие для удаления и подтверждение'
  }
};

// Определяем нужный скилл на основе текста
const textLower = text.toLowerCase();
let selectedSkill = 'create_event'; // default

if (textLower.includes('посмотр') || textLower.includes('покаж') || textLower.includes('какие')) {
  selectedSkill = 'read_events';
} else if (textLower.includes('измен') || textLower.includes('обнов') || textLower.includes('перенес')) {
  selectedSkill = 'update_event';
} else if (textLower.includes('удал') || textLower.includes('отмен') || textLower.includes('сотри')) {
  selectedSkill = 'delete_event';
}

const skill = calendarSkills[selectedSkill];

// Минимальный системный промпт для календаря (~150 токенов вместо 500+)
const systemPrompt = `Ты Calendar Agent с доступом к скиллу: ${skill.name}.
${skill.description}

Контекст диалога:
${recentHistory}

Текущий запрос: ${text}

Твоя задача: ${skill.prompt}

Отвечай кратко, по делу. Если не хватает данных - запроси их у пользователя.`;

return {
  json: {
    ...$('Orchestrator').item.json,
    calendarAgent: {
      selectedSkill: selectedSkill,
      skillDetails: skill,
      allSkills: Object.keys(calendarSkills),
      systemPrompt: systemPrompt,
      readyForLLM: true
    }
  }
};

// Default Chat Agent для обычных разговоров
// Минимальный промпт без раздувания контекста

const text = $('Orchestrator').item.json.text;
const recentHistory = $('Orchestrator').item.json.orchestrator.recentHistory;
const skillContext = $('Orchestrator').item.json.orchestrator.skillContext;

// Очень компактный промпт (~80 токенов)
const systemPrompt = `Ты дружелюбный ассистент.

Диалог:
${recentHistory}

Пользователь: ${text}

Отвечай кратко, полезно и естественно.`;

return {
  json: {
    ...$('Orchestrator').item.json,
    defaultAgent: {
      systemPrompt: systemPrompt,
      readyForLLM: true
    }
  }
};

// Merge результатов от разных агентов в единый формат

let responseText = '';
let agentName = '';

if ($input.first().json.calendarAgent && $input.first().json.calendarAgent.llmResponse) {
  responseText = $input.first().json.calendarAgent.llmResponse;
  agentName = 'Calendar Agent';
} else if ($input.first().json.defaultAgent && $input.first().json.defaultAgent.llmResponse) {
  responseText = $input.first().json.defaultAgent.llmResponse;
  agentName = 'Default Agent';
} else {
  responseText = 'Произошла ошибка при обработке запроса.';
  agentName = 'System';
}

return {
  json: {
    chatId: $input.first().json.chatId,
    messageId: $input.first().json.messageId,
    response: responseText,
    agent: agentName,
    timestamp: Date.now()
  }
};

// Отправка сервисного сообщения "Ассистент готовит ответ..."
// Будет удалено после получения ответа

const chatId = $('Merge Results').item.json.chatId;
const messageId = $('Merge Results').item.json.messageId;

return {
  json: {
    chatId: chatId,
    replyToMessageId: messageId,
    text: '⏳ Ассистент готовит ответ...',
    action: 'send_typing'
  }
};

// Обновление памяти после ответа ассистента

const memory = $('Merge Results').item.json.memory || {};
const chatId = $('Merge Results').item.json.chatId;
const response = $('Merge Results').item.json.response;
const agent = $('Merge Results').item.json.agent;
const timestamp = Date.now();

if (memory[chatId]) {
  // Добавляем ответ ассистента в историю
  memory[chatId].messages.push({
    role: 'assistant',
    content: response,
    timestamp: timestamp,
    agent: agent
  });

  // Обновляем контекст
  memory[chatId].context.currentAgent = agent;
  memory[chatId].lastActivity = timestamp;

  // Ограничиваем историю
  if (memory[chatId].messages.length > 10) {
    memory[chatId].messages = memory[chatId].messages.slice(-10);
  }
}

return {
  json: {
    updatedMemory: memory,
    success: true
  }
};

// Обработка ошибок с логированием и понятным сообщением пользователю

const errorMessage = $input.first().json.error?.message || 'Неизвестная ошибка';
const errorNode = $input.first().json.error?.node || 'Unknown';
const chatId = $input.first().json.chatId || 'unknown';

console.error(`[ERROR] Node: ${errorNode}, Message: ${errorMessage}, ChatID: ${chatId}`);

// Формируем безопасное сообщение для пользователя
let userMessage = '⚠️ Произошла ошибка при обработке вашего запроса.';

if (errorMessage.includes('timeout') || errorMessage.includes('превышен')) {
  userMessage = '⏱️ Превышено время ожидания ответа. Попробуйте еще раз.';
} else if (errorMessage.includes('credential') || errorMessage.includes('auth')) {
  userMessage = '🔐 Ошибка аутентификации. Администратор уведомлен.';
} else if (errorMessage.includes('пустое') || errorMessage.includes('empty')) {
  userMessage = '💬 Пожалуйста, отправьте сообщение с текстом.';
}

return {
  json: {
    chatId: chatId,
    errorMessage: userMessage,
    technicalError: errorMessage,
    errorNode: errorNode,
    timestamp: Date.now()
  }
};
